import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { LoanApplicationsService } from "src/app/core/services/loan-applications.service";
import { WorkFlowApp } from "../../Models/Loan/Step";
import { OfficersVisitsWorkFlow } from "../../Models/Officer/OfficerVisitsWorkFlow";
import { JobUserDocs } from "../../Models/Users/JobUserDocs";
import { AlertService } from "src/app/core/services/alert.service";
import { pagingService } from "src/app/core/services/paging.service";
interface FormStatus {
  visible: boolean;
  valid: boolean;
}
@Component({
  selector: "app-display-doc-steps",
  templateUrl: "./display-doc-steps.page.html",
  styleUrls: ["./display-doc-steps.page.scss"],
})
export class DisplayDocStepsPage implements OnInit {
  viewSteps: boolean = false;
  showLoader: boolean = false;

  workFlowApplications: WorkFlowApp[];
  lastSteps: OfficersVisitsWorkFlow[];
  currentStep: JobUserDocs[];
  page: number = 1;

  searchFormStatus: FormStatus = {
    visible: true,
    valid: false,
  };
  applicationFormStatus: FormStatus = {
    visible: false,
    valid: false,
  };
  stepsFormStatus: FormStatus = {
    visible: false,
    valid: false,
  };

  constructor(
    private formBuilder: FormBuilder,
    private loanApplicationService: LoanApplicationsService,
    private alert: AlertService,
    public pagingService: pagingService
  ) {}
  searchForm: FormGroup = this.formBuilder.group({
    nationId: [
      null,
      [
        Validators.required,
        Validators.pattern(
          "^[23](?:[0-9]{2}(?:(?:(?:0[13578]|1[02])(?:0[1-9]|[12][0-9]|3[01]))|(?:(?:0[469]|11)(?:0[1-9]|[12][0-9]|30))|(?:02(?:0[1-9]|1[0-9]|2[0-8])))|(?:(?:04|08|[2468][048]|[13579][26]|(?<=3)00)0229))(?:0[1-4]|[12][1-9]|3[1-5]|88)[0-9]{4}[1-9]$"
        ),
      ],
    ],
  });
  loanAppForm: FormGroup = this.formBuilder.group({
    applicationKey: [null],
  });

  ngOnInit() {}

  async submitForm() {
    this.searchFormStatus.valid = true;
    if (this.searchForm.valid) {
      this.showLoader = true;
      this.searchFormStatus.visible = false;
      this.applicationFormStatus.visible = true;
      this.workFlowApplications =
        await this.loanApplicationService.getWorkFlowApplications(
          this.searchForm.value.nationId.toString()
        );
      this.showLoader = false;
    }
  }

  async viewApplication(application_key: number) {
    this.showLoader = true;
    this.currentStep = await this.loanApplicationService.getJobUsersDoc(
      application_key.toString()
    );
    this.lastSteps = await this.loanApplicationService.getLastSteps(
      application_key.toString()
    );
    console.log(this.currentStep, this.lastSteps);
    if (this.currentStep.length === 0 && this.lastSteps.length === 0) {
      this.alert.showAlertError("لم يتم اتخاذ أي قرارات", false);
    } else {
      this.applicationFormStatus.visible = false;
      this.stepsFormStatus.visible = true;
    }
    this.showLoader = false;
  }

  back() {
    if (this.applicationFormStatus.visible == true) {
      this.page = 1;
      this.workFlowApplications = [];
      this.searchFormStatus.visible = true;
      this.stepsFormStatus.visible = false;
      this.applicationFormStatus.visible = false;
    } else if (this.stepsFormStatus.visible == true) {
      this.lastSteps = [];
      this.searchFormStatus.visible = false;
      this.stepsFormStatus.visible = false;
      this.applicationFormStatus.visible = true;
    }
  }

  selectedWorkflowApps(workflowApps: WorkFlowApp[]) {
    this.workFlowApplications = workflowApps;
    this.searchFormStatus.visible = false;
    this.applicationFormStatus.visible = true;
  }

  changePaginationPage = async (newPage: number) => {
    this.page = newPage;
  };
}
